module RefModule(
    input clk,
    input rst,
    input switch_in,

    output switch_out
);

reg [3:0] unused_shift_reg;
reg switch_out;

always @(posedge clk or posedge rst)
begin
  if (rst)
    unused_shift_reg <= 4'b0000;
  else
    unused_shift_reg <= {unused_shift_reg[2:0], switch_in};
end

always @(posedge clk or posedge rst)
begin
  if (rst)
    switch_out <= 0;
  else if (unused_shift_reg == 4'b1111)
    switch_out <= 1;
  else if (unused_shift_reg == 4'b0000)
    switch_out <= 0;
end

endmodule
